8: const { getNearestParentPackageJSONType } = internalBinding('modules');
9: const { getOptionValue } = require('internal/options');
10: const path = require('path');
11: const { pathToFileURL, URL } = require('internal/url');
12: const { kEmptyObject, getCWDURL } = require('internal/util');
13: const {
14:   hasUncaughtExceptionCaptureCallback,
15: } = require('internal/process/execution');
16: const {
17:   triggerUncaughtException,
18: } = internalBinding('errors');
19: const {
20:   privateSymbols: {
21:     entry_point_promise_private_symbol,
22:   },
23: } = internalBinding('util');
24: /**
25:  * Get the absolute path to the main entry point.
26:  * @param {string} main - Entry point path
27:  */
28: function resolveMainPath(main) {
29:   const defaultType = getOptionValue('--experimental-default-type');
30:   /** @type {string} */
31:   let mainPath;
32:   if (defaultType === 'module') {
33:     if (getOptionValue('--preserve-symlinks-main')) { return; }
34:     mainPath = path.resolve(main);
35:   } else {
36:     // Extension searching for the main entry point is supported only in legacy mode.
37:     // Module._findPath is monkey-patchable here.
38:     const { Module } = require('internal/modules/cjs/loader');
39:     mainPath = Module._findPath(path.resolve(main), null, true);
40:   }
41:   if (!mainPath) { return; }
42: 
43:   const preserveSymlinksMain = getOptionValue('--preserve-symlinks-main');
44:   if (!preserveSymlinksMain) {
45:     const { toRealPath } = require('internal/modules/helpers');
46:     try {
47:       mainPath = toRealPath(mainPath);
48:     } catch (err) {
49:       if (defaultType === 'module' && err?.code === 'ENOENT') {
50:         const { decorateErrorWithCommonJSHints } = require('internal/modules/esm/resolve');
51:         decorateErrorWithCommonJSHints(err, mainPath, getCWDURL());
52:       }
53:       throw err;
54:     }
55:   }
56: 
57:   return mainPath;
58: }
59: 
60: /**
61:  * Determine whether the main entry point should be loaded through the ESM Loader.
62:  * @param {string} mainPath - Absolute path to the main entry point
63:  */
64: function shouldUseESMLoader(mainPath) {
65:   if (getOptionValue('--experimental-default-type') === 'module') { return true; }
66: 
67:   /**
68:    * @type {string[]} userLoaders A list of custom loaders registered by the user
69:    * (or an empty list when none have been registered).
70:    */
71:   const userLoaders = getOptionValue('--experimental-loader');
72:   /**
73:    * @type {string[]} userImports A list of preloaded modules registered by the user
74:    * (or an empty list when none have been registered).
75:    */
76:   const userImports = getOptionValue('--import');
77:   if (userLoaders.length > 0 || userImports.length > 0) { return true; }
78: 
79:   // Determine the module format of the entry point.
80:   if (mainPath && StringPrototypeEndsWith(mainPath, '.mjs')) { return true; }
81:   if (!mainPath || StringPrototypeEndsWith(mainPath, '.cjs')) { return false; }
82: 
83:   if (getOptionValue('--experimental-strip-types')) {
84:     // This ensures that --experimental-default-type=commonjs and .mts files are treated as commonjs
85:     if (getOptionValue('--experimental-default-type') === 'commonjs') { return false; }
86:     if (!mainPath || StringPrototypeEndsWith(mainPath, '.cts')) { return false; }
87:     // This will likely change in the future to start with commonjs loader by default
88:     if (mainPath && StringPrototypeEndsWith(mainPath, '.mts')) { return true; }
89:   }
90: 
91:   const type = getNearestParentPackageJSONType(mainPath);
92: 
93:   // No package.json or no `type` field.
94:   if (type === undefined || type === 'none') {
95:     return false;
96:   }
97: 
98:   return type === 'module';
99: }
100: 
101: /**
102:  * @param {function(ModuleLoader):ModuleWrap|undefined} callback
103:  */
104: async function asyncRunEntryPointWithESMLoader(callback) {
105:   const cascadedLoader = require('internal/modules/esm/loader').getOrInitializeCascadedLoader();
106:   try {
107:     const userImports = getOptionValue('--import');
108:     if (userImports.length > 0) {
109:       const parentURL = getCWDURL().href;
110:       for (let i = 0; i < userImports.length; i++) {
111:         await cascadedLoader.import(userImports[i], parentURL, kEmptyObject);
112:       }
113:     } else {
114:       cascadedLoader.forceLoadHooks();
115:     }
116:     await callback(cascadedLoader);
117:   } catch (err) {
118:     if (hasUncaughtExceptionCaptureCallback()) {
119:       process._fatalException(err);
120:       return;
121:     }
122:     triggerUncaughtException(
123:       err,
124:       true, /* fromPromise */
125:     );
126:   }
127: }
128: 
129: /**
130:  * This initializes the ESM loader and runs --import (if any) before executing the
131:  * callback to run the entry point.
132:  * If the callback intends to evaluate a ESM module as entry point, it should return
133:  * the corresponding ModuleWrap so that stalled TLA can be checked a process exit.
134:  * @param {function(ModuleLoader):ModuleWrap|undefined} callback
135:  * @returns {Promise}
136:  */
137: function runEntryPointWithESMLoader(callback) {
138:   const promise = asyncRunEntryPointWithESMLoader(callback);
139:   // Register the promise - if by the time the event loop finishes running, this is
140:   // still unsettled, we'll search the graph from the entry point module and print
141:   // the location of any unsettled top-level await found.
142:   globalThis[entry_point_promise_private_symbol] = promise;
143:   return promise;
144: }
145: 
146: /**
147:  * Parse the CLI main entry point string and run it.
148:  * For backwards compatibility, we have to run a bunch of monkey-patchable code that belongs to the CJS loader (exposed
149:  * by `require('module')`) even when the entry point is ESM.
150:  * This monkey-patchable code is bypassed under `--experimental-default-type=module`.
151:  * Because of backwards compatibility, this function is exposed publicly via `import { runMain } from 'node:module'`.
152:  * Because of module detection, this function will attempt to run ambiguous (no explicit extension, no
153:  * `package.json` type field) entry points as CommonJS first; under certain conditions, it will retry running as ESM.
154:  * @param {string} main - First positional CLI argument, such as `'entry.js'` from `node entry.js`
155:  */
156: function executeUserEntryPoint(main = process.argv[1]) {
157:   let useESMLoader;
158:   let resolvedMain;
159:   if (getOptionValue('--entry-url')) {
160:     useESMLoader = true;
161:   } else {
162:     resolvedMain = resolveMainPath(main);
163:     useESMLoader = shouldUseESMLoader(resolvedMain);
164:   }
165:   // Unless we know we should use the ESM loader to handle the entry point per the checks in `shouldUseESMLoader`, first
166:   // try to run the entry point via the CommonJS loader; and if that fails under certain conditions, retry as ESM.
167:   if (!useESMLoader) {
168:     const cjsLoader = require('internal/modules/cjs/loader');
169:     const { wrapModuleLoad } = cjsLoader;
170:     wrapModuleLoad(main, null, true);
171:   } else {
172:     const mainPath = resolvedMain || main;
173:     const mainURL = getOptionValue('--entry-url') ? new URL(mainPath, getCWDURL()) : pathToFileURL(mainPath);
174: 
175:     runEntryPointWithESMLoader((cascadedLoader) => {
176:       // Note that if the graph contains unsettled TLA, this may never resolve
177:       // even after the event loop stops running.
178:       return cascadedLoader.import(mainURL, undefined, { __proto__: null }, true);
179:     });
180:   }
181: }
182: 
183: module.exports = {
184:   executeUserEntryPoint,
185:   runEntryPointWithESMLoader,
186: };
