12: /**
13:  * Generate a function to be used as import.meta.resolve for a particular module.
14:  * @param {string} defaultParentURL The default base to use for resolution
15:  * @param {typeof import('./loader.js').ModuleLoader} loader Reference to the current module loader
16:  * @param {bool} allowParentURL Whether to permit parentURL second argument for contextual resolution
17:  * @returns {(specifier: string) => string} Function to assign to import.meta.resolve
18:  */
19: function createImportMetaResolve(defaultParentURL, loader, allowParentURL) {
20:   /**
21:    * @param {string} specifier
22:    * @param {URL['href']} [parentURL] When `--experimental-import-meta-resolve` is specified, a
23:    * second argument can be provided.
24:    */
25:   return function resolve(specifier, parentURL = defaultParentURL) {
26:     let url;
27: 
28:     if (!allowParentURL) {
29:       parentURL = defaultParentURL;
30:     }
31: 
32:     try {
33:       ({ url } = loader.resolveSync(specifier, parentURL));
34:       return url;
35:     } catch (error) {
36:       switch (error?.code) {
37:         case 'ERR_UNSUPPORTED_DIR_IMPORT':
38:         case 'ERR_MODULE_NOT_FOUND':
39:           ({ url } = error);
40:           if (url) {
41:             return url;
42:           }
43:       }
44:       throw error;
45:     }
46:   };
47: }
