30: function createExport(expt, index) {
31:   const nameStringLit = JSONStringify(expt);
32:   return `let $export_${index};
33: export { $export_${index} as ${nameStringLit} };
34: import.meta.exports[${nameStringLit}] = {
35:   get: () => $export_${index},
36:   set: (v) => $export_${index} = v,
37: };`;
