40: /**
41:  * Creates a dynamic module with the given imports, exports, URL, and evaluate function.
42:  * @param {string[]} imports - An array of imports.
43:  * @param {string[]} exports - An array of exports.
44:  * @param {string} [url=''] - The URL of the module.
45:  * @param {(reflect: DynamicModuleReflect) => void} evaluate - The function to evaluate the module.
46:  * @typedef {object} DynamicModuleReflect
47:  * @property {string[]} imports - The imports of the module.
48:  * @property {string[]} exports - The exports of the module.
49:  * @property {(cb: (reflect: DynamicModuleReflect) => void) => void} onReady - Callback to evaluate the module.
50:  */
51: const createDynamicModule = (imports, exports, url = '', evaluate) => {
52:   debug('creating ESM facade for %s with exports: %j', url, exports);
53:   const source = `
54: ${ArrayPrototypeJoin(ArrayPrototypeMap(imports, createImport), '\n')}
55: ${ArrayPrototypeJoin(ArrayPrototypeMap(exports, createExport), '\n')}
56: import.meta.done();
57: `;
58:   const { registerModule, compileSourceTextModule } = require('internal/modules/esm/utils');
59:   const m = compileSourceTextModule(`${url}`, source);
60: 
61:   const readyfns = new SafeSet();
62:   /** @type {DynamicModuleReflect} */
63:   const reflect = {
64:     exports: { __proto__: null },
65:     onReady: (cb) => { readyfns.add(cb); },
66:   };
67: 
68:   if (imports.length) {
69:     reflect.imports = { __proto__: null };
70:   }
71:   registerModule(m, {
72:     __proto__: null,
73:     initializeImportMeta: (meta, wrap) => {
74:       meta.exports = reflect.exports;
75:       if (reflect.imports) {
76:         meta.imports = reflect.imports;
77:       }
78:       meta.done = () => {
79:         evaluate(reflect);
80:         reflect.onReady = (cb) => cb(reflect);
81:         for (const fn of readyfns) {
82:           readyfns.delete(fn);
83:           fn(reflect);
84:         }
85:       };
86:     },
87:   });
88: 
89:   return {
90:     module: m,
91:     reflect,
92:   };
93: };
94: 
95: module.exports = createDynamicModule;
